# ANTI-PATTERN: Redundant API calls, no caching, brittle error handling
class BattingAnalyzerAntiPattern:
    def __init__(self, api_key):
        self.client = OpenAI(api_key=api_key)

    def analyze_batsman(self, batsman_name, stats):
        # Calls API every time, even for same query
        response = self.client.chat.completions.create(
            model="gpt-4",
            messages=[{
                "role": "user",
                "content": f"Analyze {batsman_name} batting stats: {stats}"
            }]
        )
        return response.choices[0].message.content

# BEST PRACTICE: Caching, routing, fallback patterns
class BattingAnalyzerBestPractice:
    def __init__(self, api_key):
        self.client = OpenAI(api_key=api_key)
        self.cache = {}  # Simple cache; use Redis in production
        self.embedding_model = "text-embedding-3-small"

    def analyze_batsman(self, batsman_name, stats, use_rag=True):
        # Check cache first
        cache_key = f"{batsman_name}_{hash(str(stats))}"
        if cache_key in self.cache:
            return self.cache[cache_key]

        # Route based on query complexity
        complexity = self._estimate_complexity(stats)
        model = "gpt-4" if complexity > 0.7 else "gpt-3.5-turbo"

        # Build context with RAG if enabled
        context = ""
        if use_rag:
            context = self._retrieve_similar_batsmen(batsman_name, stats)

        try:
            response = self.client.chat.completions.create(
                model=model,
                messages=[{
                    "role": "system",
                    "content": "You are a cricket statistics expert. Use the provided context.",
                }, {
                    "role": "user",
                    "content": f"Context:\n{context}\n\nAnalyze {batsman_name}: {stats}"
                }],
                temperature=0.3,
                max_tokens=500
            )
            result = response.choices[0].message.content
            self.cache[cache_key] = result  # Store result
            return result
        except RateLimitError:
            return self._fallback_cached_analysis(batsman_name)

    def _estimate_complexity(self, stats):
        # Return 0-1 complexity score
        return min(len(str(stats)) / 1000, 1.0)

